import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XssSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability');</script>";

        // Properly handling user input by encoding it
        String encodedUserInput = Encode.forHtml(userInput);
        String output = "<p>User input: " + encodedUserInput + "</p>";

        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println(output);
            out.close();
            System.out.println("Output generated successfully.");
        } catch (IOException e) {
            System.out.println("Error writing output.");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
